fn intDigits(d) {
  let parts = split(toString(d), ".")
  return parts[0]
}
fn groupDigits(ds) {
  let n = length(ds)
  if (n <= 3) {
    return ds
  }
  let out = ""
  let i = 0
  while (i < n) {
    if (i > 0) {
      if ((n - i) % 3 == 0) {
        out = out + " "
      }
    }
    out = out + substring(ds, i, i + 1)
    i = i + 1
  }
  return out
}
fn money(n) {
  let neg = false
  let v = n
  if (v < 0) {
    neg = true
    v = -v
  }
  let cents = round(v * 100)
  let whole = floor(cents / 100)
  let frac = cents - whole * 100
  let fracStr = intDigits(frac)
  if (frac < 10) {
    fracStr = "0" + fracStr
  }
  let s = groupDigits(intDigits(whole)) + "," + fracStr + " €"
  if (neg) {
    s = "-" + s
  }
  return s
}
