fn loadTx() {
  let raw = storage.getItem("finances_tx")
  if (raw == null) {
    return []
  }
  let parsed = jsonParse(raw)
  if (parsed == null) {
    return []
  }
  return parsed
}
fn persistTx(items) {
  storage.setItem("finances_tx", jsonStringify(items))
}
fn sumByType(items, type) {
  let total = 0
  items.forEach(fn(t, i) {
    if (t.type == type) {
      total = total + t.amount
    }
  })
  return 0
}
fn monthItems(items) {
  let m = month()
  let y = year()
  let out = []
  items.forEach(fn(t, i) {
    if (month(t.date) == m) {
      if (year(t.date) == y) {
        out.add(t)
      }
    }
  })
  return out
}
fn expenseByCategory(items) {
  let out = []
  categoriesFor("expense").forEach(fn(c, i) {
    let total = 0
    items.forEach(fn(t, j) {
      if (t.type == "expense") {
        if (t.category == c.key) {
          total = total + t.amount
        }
      }
    })
    if (total > 0) {
      out.add({
        key: c.key,
        label: c.label,
        emoji: c.emoji,
        color: c.color,
        total: total
      })
    }
  })
  return out
}
