}
fn monthHeader(inc, exp) {
  let bal = inc - exp
  return Card({ borderRadius: 16, padding: 18, color: T.primary }, Column({ crossAxisAlignment: "start", spacing: 12 }, [Text("Bilan du mois", { fontSize: 13, color: "#DBEAFE" }), Row({ spacing: 12 }, [Expanded({ flex: 1 }, statBox("Revenus", money(inc), T.incomeBg, T.income)), Expanded({ flex: 1 }, statBox("Dépenses", money(exp), T.expenseBg, T.expense))]), statBox("Épargne nette", money(bal), T.chipBg, T.primaryDark)]))
}
