}
fn categoryBar(c, totalExp) {
  let pct = 0
  if (totalExp > 0) {
    pct = floor(c.total * 100 / totalExp)
  }
  let fillFlex = pct
  if (fillFlex < 1) {
    fillFlex = 1
  }
  let restFlex = 100 - pct
  if (restFlex < 1) {
    restFlex = 1
  }
  return Box({ color: T.surface, borderRadius: 14, padding: 14 }, Column({ spacing: 10, crossAxisAlignment: "start" }, [Row({ crossAxisAlignment: "center", spacing: 10 }, [catAvatar(c, 34), Expanded({ flex: 1 }, Text(c.label, { fontSize: 14, fontWeight: "600", color: T.text })), Text(money(c.total), { fontSize: 14, fontWeight: "bold", color: T.text })]), Row({ crossAxisAlignment: "center", spacing: 10 }, [Expanded({ flex: 1 }, Box({ color: T.bg, borderRadius: 6 }, Row({}, [Expanded({ flex: fillFlex }, Box({ color: c.color, borderRadius: 6, height: 10 })), Expanded({ flex: restFlex }, Box({ height: 10 }))]))), Text(intDigits(pct) + "%", { fontSize: 12, fontWeight: "600", color: T.muted })])]))
}
fn sortByTotalDesc(arr) {
  let items = []
  arr.forEach(fn(c, i) {
    items.add(c)
  })
  let out = []
  while (items.length > 0) {
    let bestIdx = 0
    let best = items[0]
    let i = 1
    while (i < items.length) {
      if (items[i].total > best.total) {
        best = items[i]
        bestIdx = i
      }
      i = i + 1
    }
    out.add(best)
    let rest = []
    let j = 0
    while (j < items.length) {
      if (j != bestIdx) {
        rest.add(items[j])
      }
      j = j + 1
    }
    items = rest
  }
  return out
}
